#!/usr/bin/env python3
"""NEXUS Fast Port Scanner"""
import socket
import sys
from concurrent.futures import ThreadPoolExecutor, as_completed
from datetime import datetime

def scan_port(host: str, port: int, timeout: float = 0.5) -> tuple:
    try:
        with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
            s.settimeout(timeout)
            result = s.connect_ex((host, port))
            if result == 0:
                try:
                    service = socket.getservbyport(port)
                except:
                    service = '?'
                return port, True, service
    except:
        pass
    return port, False, ''

def scan(host: str, start: int = 1, end: int = 1024, threads: int = 200):
    print(f'[*] Scanning {host} ports {start}-{end}')
    print(f'[*] Started: {datetime.now()}')
    open_ports = []
    with ThreadPoolExecutor(max_workers=threads) as ex:
        futures = {ex.submit(scan_port, host, p): p for p in range(start, end+1)}
        for f in as_completed(futures):
            port, is_open, service = f.result()
            if is_open:
                print(f'  [OPEN] {port}/tcp  {service}')
                open_ports.append(port)
    print(f'[+] Done: {len(open_ports)} open ports found')
    return open_ports

if __name__ == '__main__':
    target = sys.argv[1] if len(sys.argv) > 1 else '127.0.0.1'
    end = int(sys.argv[2]) if len(sys.argv) > 2 else 1024
    scan(target, end=end)
