#!/usr/bin/env python3
"""NEXUS Subdomain Aggregator"""
import subprocess
import requests
import json
import sys
from pathlib import Path

def crtsh(domain):
    try:
        r = requests.get(f'https://crt.sh/?q=%.{domain}&output=json', timeout=15)
        return {n.replace('*.','') for e in r.json() for n in e['name_value'].split('\n')}
    except:
        return set()

def subfinder(domain):
    try:
        r = subprocess.run(['subfinder','-d',domain,'-silent'],
                           capture_output=True, text=True, timeout=60)
        return set(r.stdout.strip().split('\n')) if r.stdout.strip() else set()
    except:
        return set()

def amass(domain):
    try:
        r = subprocess.run(['amass','enum','-passive','-d',domain,'-silent'],
                           capture_output=True, text=True, timeout=120)
        return set(r.stdout.strip().split('\n')) if r.stdout.strip() else set()
    except:
        return set()

def run(domain):
    print(f'[*] Gathering subdomains for: {domain}')
    all_subs = set()
    for name, fn in [('crt.sh', crtsh), ('subfinder', subfinder), ('amass', amass)]:
        subs = fn(domain)
        print(f'  {name}: {len(subs)} found')
        all_subs |= subs
    all_subs = {s for s in all_subs if s and domain in s}
    out = Path(f'subs_{domain}.txt')
    out.write_text('\n'.join(sorted(all_subs)))
    print(f'[+] Total unique: {len(all_subs)} → {out}')
    return sorted(all_subs)

if __name__ == '__main__':
    run(sys.argv[1] if len(sys.argv) > 1 else 'example.com')
```

