#!/usr/bin/env python3
"""NEXUS Network Scanner → HTML Report"""
import subprocess, json, sys
from pathlib import Path
from datetime import datetime

def nmap_scan(target):
    r = subprocess.run(
        ['nmap', '-sV', '-sC', '--open', '-T4', '-oJ', '-', target],
        capture_output=True, text=True
    )
    try:
        return json.loads(r.stdout)
    except:
        return {}

def to_html(data, target):
    ts = datetime.now().strftime('%Y-%m-%d %H:%M')
    rows = ''
    for host in data.get('hosts', []):
        for port in host.get('ports', []):
            if port.get('state') == 'open':
                rows += f"<tr><td>{host.get('addr','?')}</td><td>{port['id']}/{port['protocol']}</td>"
                rows += f"<td>{port.get('service',{}).get('name','?')}</td>"
                rows += f"<td>{port.get('service',{}).get('product','')} {port.get('service',{}).get('version','')}</td></tr>"
    return f"""<!DOCTYPE html><html><head><title>NEXUS Scan {target}</title>
<style>body{{font-family:monospace;background:#111;color:#0f0}}table{{width:100%;border-collapse:collapse}}
th,td{{border:1px solid #333;padding:8px;text-align:left}}th{{background:#222}}</style></head><body>
<h1>NEXUS CyberHackSecurity Scan Report</h1>
<p>Target: {target} | Time: {ts}</p>
<table><tr><th>IP</th><th>Port</th><th>Service</th><th>Version</th></tr>{rows}</table>
</body></html>"""

if __name__ == '__main__':
    target = sys.argv[1]
    print(f'[*] Scanning {target}...')
    data = nmap_scan(target)
    html = to_html(data, target)
    out = Path(f'report_{target}_{datetime.now().strftime("%Y%m%d_%H%M")}.html')
    out.write_text(html)
    print(f'[+] Report: {out}')
